// src/pages/ngo/admin/RegisterPage.jsx
import React, { useState } from 'react';
import { donorApi } from '../../../services/api';

export default function RegisterDonor() {
  const [form, setForm] = useState({
    userCert: '',
    donorId: '',
    name: '',
    email: '',
    alias: '',
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);

  const onChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    try {
      const res = await donorApi.registerDonor(form);
      setMessage(res?.data || 'Donor registered successfully');
    } catch (err) {
      setMessage(err?.response?.data?.error || err.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{ maxWidth: 800, margin: '0 auto' }}>
      <div>
        <label>User Cert</label>
        <input
          name="userCert"
          value={form.userCert}
          onChange={onChange}
          placeholder="userCert"
          required
        />
      </div>

      <div>
        <label>Donor ID</label>
        <input
          name="donorId"
          value={form.donorId}
          onChange={onChange}
          placeholder="donorId"
          required
        />
      </div>

      <div>
        <label>Name</label>
        <input
          name="name"
          value={form.name}
          onChange={onChange}
          placeholder="name"
          required
        />
      </div>

      <div>
        <label>Email</label>
        <input
          name="email"
          value={form.email}
          onChange={onChange}
          placeholder="email"
          type="email"
          required
        />
      </div>

      <div>
        <label>Alias</label>
        <input
          name="alias"
          value={form.alias}
          onChange={onChange}
          placeholder="alias"
        />
      </div>

      <button type="submit" disabled={loading}>
        {loading ? 'Sending...' : 'Send Request'}
      </button>

      {message && <div style={{ marginTop: 12 }}>{String(message)}</div>}
    </form>
  );
}
